//! Hebbian graph persistence utilities — called at startup by main.rs.
//!
//! L1 (LexicalGraph) is now embedded in each Router struct (router.l1()).
//! L2 (IntentIndex) is now embedded in each Router struct (router.l2()).
//!
//! These utilities remain for loading the global L1 base graph from disk.

use asv_router::scoring::LexicalGraph;

/// Load the global L1 base graph (data/l1_base.json), generated by
/// scripts/generate_l1_base.py. Contains WordNet morphology + synonyms
/// and ConceptNet relations. Shared across all namespaces.
pub fn load_l1_base(data_dir: &str) -> Option<LexicalGraph> {
    let path = format!("{}/l1_base.json", data_dir);
    match LexicalGraph::load(&path) {
        Ok(g) => {
            let edge_count: usize = g.edges.values().map(|v| v.len()).sum();
            println!("Loaded L1 base graph: {} terms, {} edges", g.edges.len(), edge_count);
            Some(g)
        }
        Err(e) => {
            println!("L1 base graph not found at {} ({}) — run scripts/generate_l1_base.py to generate it", path, e);
            None
        }
    }
}
